&lt;p&gt;सही उत्तर &lt;strong&gt;&amp;#39;वात्सल्य&amp;#39;&lt;/strong&gt; है&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;भरतमुनि द्वारा उल्लिखित आठ स्थायी भावों में &lt;strong&gt;&amp;#39;वात्सल्य&amp;#39; शामिल&lt;/strong&gt; &lt;strong&gt;नहीं &lt;/strong&gt;है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;नाट्यशास्त्र में भरतमुनि ने रसों की संख्या &lt;strong&gt;आठ&lt;/strong&gt; मानी है- &lt;strong&gt;शृंगार, हास्य, करुण, रौद्र, वीर, भयानक, वीभत्स, अद्भुत।&lt;/strong&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;भरतमुनि ने &lt;strong&gt;नाट्यशास्त्र&lt;/strong&gt; नामक ग्रंथ लिखा।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;इनके द्वारा रचित ग्रंथ &amp;#39;नाट्यशास्त्र&amp;#39; भारतीय नाट्य और काव्यशास्त्र का आदिग्रन्थ है।&lt;/li&gt;
	&lt;li&gt;इसमें सर्वप्रथम रस सिद्धांत की चर्चा तथा इसके प्रसिद्ध सूत्र -&lt;strong&gt;&amp;#39;विभावानुभाव संचारीभाव संयोगद्रस निष्पति:&amp;quot; &lt;/strong&gt;की स्थापना की गयी है&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;3&quot; style=&quot;width: 310px; height: 27px;&quot;&gt;
			&lt;p style=&quot;margin-left: 5.4pt; text-align: justify;&quot;&gt;काव्य को पढ़ने, सुनने से उत्पन्न होने वाले आनंद की अनुभूति को साहित्य के अंतर्गत रह कहा जाता है।&amp;nbsp;हिंदी में &amp;lsquo;स्थायी भाव&amp;rsquo; के आधार पर काव्य में &lt;strong&gt;&amp;lsquo;नौ&amp;rsquo; रस &lt;/strong&gt;बताए गए हैं, जो निम्नलिखित हैं:-&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
