&lt;p&gt;सही उत्तर&lt;strong&gt;&amp;nbsp;कर्तृ वाच्य&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;है&lt;/span&gt;&lt;span style=&quot; user-select: auto;&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot; user-select: auto;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;मैं रामायण नहीं पढ़ सका।&amp;#39; वाक्य में कर्तृ वाच्य&lt;strong&gt; &lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;&amp;#39;मैं रामायण नहीं पढ़ सका।&amp;#39; वाक्य में &amp;#39;&lt;u&gt;&lt;strong&gt;मै&amp;#39;&lt;/strong&gt;&lt;/u&gt; कर्ता की प्रमुखता है&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

