			&lt;td style=&quot;width: 258px; height: 8px; user-select: auto;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;user-select: auto;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;user-select: auto;&quot;&gt;&lt;span style=&quot;user-select: auto;&quot;&gt;परिभाषा&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 168px; height: 8px; user-select: auto;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;user-select: auto;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;user-select: auto;&quot;&gt;&lt;span style=&quot;user-select: auto;&quot;&gt;उदाहरण&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr style=&quot;user-select: auto;&quot;&gt;
			&lt;td style=&quot;width: 60px; height: 76px; user-select: auto;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left: 4.9pt; user-select: auto;&quot;&gt;&lt;span style=&quot;user-select: auto;&quot;&gt;कर्तृवाच्य&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 258px; height: 76px; user-select: auto;&quot;&gt;
			&lt;p style=&quot;margin-left: 4.9pt; user-select: auto;&quot;&gt;&lt;span style=&quot;box-sizing: inherit; border: 0px; font-style: inherit; margin: 0px; outline: 0px; padding: 0px; vertical-align: baseline; user-select: auto;&quot;&gt;जिस वाक्य में कर्ता मुख्य हो और क्रिया कर्ता के&amp;nbsp;लिंग, वचन एवं पुरूष के अनुसार हो, उसे कर्तृवाच्य&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;box-sizing: inherit; border: 0px; font-style: inherit; margin: 0px; outline: 0px; padding: 0px; vertical-align: baseline; user-select: auto;&quot;&gt;कहते है।&lt;/span&gt;&lt;/p&gt;
