&lt;p&gt;वाक्य में रेखांकित शब्द में क्रिया विशेषण- &lt;strong&gt;&amp;quot;कालवाचक क्रिया विशेषण।&amp;quot; &lt;/strong&gt;अन्य विकल्प अनुचित है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;quot;ठाकुर साहब &lt;u&gt;रोज़&lt;/u&gt; व्यायाम करते हैं।&amp;quot;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;वाक्य में रेखांकित शब्द में क्रिया विशेषण-&lt;strong&gt; &amp;quot;कालवाचक क्रिया विशेषण।&amp;quot;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;प्रकार&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;परिभाषा&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;उदाहरण&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;कालवाचक क्रिया विशेषण&lt;/td&gt;
			&lt;td&gt;जिस क्रिया विशेषण से क्रिया के होने के समय का पता चलता है उसे कालवाचक क्रिया विशेषण कहते हैं।&lt;/td&gt;
			&lt;td&gt;ठाकुर साहब रोज़ व्यायाम करते हैं।&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;प्रकार&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;परिभाषा&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;उदाहरण&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;परिमाणवाचक क्रिया विशेषण&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;जो अविकारी शब्द किसी क्रिया के परिमाण अथवा निश्चित संख्या का बोध कराते हैं, उन्हें परिमाणवाचक क्रिया विशेषण कहते हैं।&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;एक-एक करके, पर्याप्त; आदि ,जितना कुछ।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;रीतिवाचक क्रिया विशेषण&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;जो अविकारी शब्द किसी क्रिया की रीति का बोध कराते हैं, उन्हें रीतिवाचक क्रिया विशेषण कहते हैं।&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कदापि, तो, हो, मात्र, भर आदि।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;स्थानवाचक क्रिया विशेषण&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ऐसे अविकारी शब्द जो हमें क्रियाओं के होने के स्थान का बोध कराते हैं, वे शब्द स्थानवाचक क्रिया विशेषण कहलाते हैं।&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;अन्दर, बाहर, छत पर, पेड़ पर, दूर आदि।&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;वाक्य शुद्ध है-&amp;nbsp;&lt;strong&gt;&lt;u&gt;व्यायाम करने से&amp;nbsp;शरीर पुष्ट होता है।&lt;/u&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;उपरोक्त में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;लिंग, वचन, वर्तनी,&amp;nbsp;कारक&amp;nbsp;&lt;/span&gt;तथा&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;क्रिया&lt;/span&gt;&amp;nbsp;का सही रुप में प्रयोग किया गया।&amp;nbsp;&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;अन्य सभी विकल्प व्याकरण की दृष्टि से अशुद्ध है&lt;span style=&quot;&quot;&gt;।&amp;nbsp;&amp;nbsp;&lt;/span&gt;&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;अशुद्ध रूप -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;u&gt;&lt;strong&gt;कृपया&lt;/strong&gt;&lt;/u&gt; मुझे भी सुनने की &lt;strong&gt;&lt;u&gt;कृपा&lt;/u&gt;&lt;/strong&gt; करें।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;शुद्ध रूप -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;मुझे भी सुनने की&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&lt;u&gt;कृपा&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;करें। &lt;strong&gt;(&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;पुनरावृत्ति की अशुद्धि)&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;अशुद्ध रूप -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;strong&gt;&lt;u&gt;यह&lt;/u&gt;&lt;/strong&gt; बच्चे कहाँ के रहने वाले हैं।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;शुद्ध रूप -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;strong&gt;&lt;u&gt;ये&lt;/u&gt;&amp;nbsp;&lt;/strong&gt;बच्चे कहाँ के रहने वाले&amp;nbsp;हैं।&lt;strong&gt; (&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;वचन&amp;nbsp;व&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;क्रिया&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;संबंधी अशुद्धि)&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;अशुद्ध रूप -&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;हमने&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;उन्हें आज भोजन &lt;u&gt;&lt;strong&gt;पर बुलाए है।&lt;/strong&gt;&lt;/u&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot; font-weight: 700;&quot;&gt;शुद्ध रूप -&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;हमने उन्हें आज भोजन &lt;u&gt;&lt;strong&gt;करने&amp;nbsp;के लिए&amp;nbsp;बुलाया&amp;nbsp;है।&lt;/strong&gt;&lt;/u&gt; &lt;u&gt;&lt;strong&gt;(&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;कारक व&amp;nbsp;क्रिया&amp;nbsp;संबंधी अशुद्धि)&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पुनरावृत्ति की अशुद्धि:-&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;एक ही&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;वाक्य&amp;nbsp;&lt;/span&gt;में जब&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;एक ही अर्थ/भाव को प्रकट&lt;/span&gt;&amp;nbsp;करने वाले&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;दो शब्दों&lt;/span&gt;&amp;nbsp;का प्रयोग कर दिया जाता है तो वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;अशुद्ध&amp;nbsp;&lt;/span&gt;हो जाता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण -&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अशुद्ध रूप -&amp;nbsp;&lt;/span&gt;जयपुर में कई&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;दर्शनीय&lt;/span&gt;&lt;/u&gt;&amp;nbsp;स्थल&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;देखने योग्य&lt;/u&gt;&amp;nbsp;&lt;/span&gt;हैं।&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शुद्ध रूप -&amp;nbsp;&lt;/span&gt;जयपुर में कई&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;दर्शनीय&lt;/u&gt;&lt;/span&gt;&amp;nbsp;स्थल हैं।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;वचन संबंधी अशुद्धि:-&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;कभी-कभी देखा गया है कि वाक्यों में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;वचन संबंधी गलत प्रयोग&amp;nbsp;&lt;/span&gt;भी किए जाते हैं।&lt;/li&gt;
				&lt;li&gt;इन्हें वाक्य की&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;वचन संबंधी अशुद्धि&lt;/span&gt;&amp;nbsp;कहा जाता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण -&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अशुद्ध रूप -&amp;nbsp;&lt;/span&gt;मैं तो&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;आपका&lt;/span&gt;&lt;/u&gt;&amp;nbsp;दर्शन करने आया हूँ।&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शुद्ध रूप -&amp;nbsp;&lt;/span&gt;मैं तो&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;आपके&lt;/span&gt;&lt;/u&gt;&amp;nbsp;दर्शन करने आया हूँ।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;कारक संबंधी अशुद्धि:-&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;वाक्यों में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;कारक संबंधी गलत प्रयोग&lt;/span&gt;&amp;nbsp;भी किए जाते हैं, जिस कारण वाक्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;अशुद्ध&amp;nbsp;&lt;/span&gt;हो जाता है।&lt;/li&gt;
				&lt;li&gt;इन अशुद्धियों को&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;कारक संबंधी अशुद्धियाँ&amp;nbsp;&lt;/span&gt;कहा जाता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जैसे -&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अशुद्ध रूप -&lt;/span&gt;&amp;nbsp;शिष्य यज्ञ&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;को&lt;/u&gt;&lt;/span&gt;&amp;nbsp;लकड़ी लाया।&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;शुद्ध रूप -&lt;/span&gt;&amp;nbsp;शिष्य यज्ञ&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;के लिए&lt;/u&gt;&lt;/span&gt;&amp;nbsp;लकड़ी लाया।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;क्रिया संबंधी अशुद्धि:-&lt;/span&gt;&lt;/p&gt;

			&lt;ul style=&quot;&quot;&gt;
				&lt;li&gt;वाक्य में&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;क्रिया&lt;/span&gt;&amp;nbsp;का प्रयोग&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;कर्ता के लिंग&lt;/span&gt;&amp;nbsp;एवं&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;वचन के अनुसार&lt;/span&gt;&amp;nbsp;किया जाता है अन्यथा वह&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;वाक्य अशुद्ध&lt;/span&gt;&amp;nbsp;समझा जाता है।&lt;/li&gt;
				&lt;li&gt;इस&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;अशुद्धि&lt;/span&gt;&amp;nbsp;को वाक्य की&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;क्रिया संबंधी अशुद्धि&lt;/span&gt;&amp;nbsp;कहा जाता है।&lt;/li&gt;
			&lt;/ul&gt;

			&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;उदाहरण -&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;अशुद्ध रूप -&lt;/strong&gt;&amp;nbsp;प्रतीक्षा &lt;u&gt;&lt;strong&gt;देखना&lt;/strong&gt;&lt;/u&gt;।&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;शुद्ध रूप -&lt;/strong&gt;&amp;nbsp;प्रतीक्षा &lt;strong&gt;&lt;u&gt;करना&lt;/u&gt;&lt;/strong&gt;।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;#39;सच्चरित्र&amp;#39; शब्द में &lt;strong&gt;सत्&lt;/strong&gt; उपसर्ग है।&lt;/p&gt;

&lt;p&gt;अन्य सभी विकल्प &lt;strong&gt;असंगत&lt;/strong&gt; है।&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सही संधि विच्छेद&lt;strong&gt; सत् + चरित्र =&amp;nbsp;सच्चरित्र &lt;/strong&gt;होगा।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;सच्चरित्र में &lt;strong&gt;व्यंजन संधि &lt;/strong&gt;है।&lt;/li&gt;
	&lt;li&gt;इस प्रश्न में व्यंजन संधि के&lt;strong&gt; त् संबंधी&lt;/strong&gt; नियम लागू होता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;नियम है:-&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;त् &lt;/strong&gt;के बाद यदि &lt;strong&gt;च, छ,&lt;/strong&gt;&amp;nbsp; हो तो &lt;strong&gt;त्&lt;/strong&gt;&amp;nbsp;का &lt;strong&gt;च्&lt;/strong&gt; हो जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जैसे:-&lt;/strong&gt;
	&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:250px;&quot;&gt;
		&lt;tbody&gt;
			&lt;tr&gt;
				&lt;td&gt;&lt;strong&gt;शब्द&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
				&lt;td&gt;&lt;strong&gt;संधि विच्छेद&lt;/strong&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;उच्चारण&lt;/td&gt;
				&lt;td&gt;उत्&amp;nbsp; + चारण&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;उच्चरित&lt;/td&gt;
				&lt;td&gt;उत् + चरित&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;जगच्छाया&lt;/td&gt;
				&lt;td&gt;जगत् + छाया&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;&lt;strong&gt;व्यंजन संधि:- &lt;/strong&gt;व्यंजन के बाद &lt;strong&gt;स्वर या व्यंजन &lt;/strong&gt;आने से जो &lt;strong&gt;परिवर्तन&lt;/strong&gt; होता है, उसे &lt;strong&gt;व्यंजन संधि&lt;/strong&gt; कहते है।&lt;span style=&quot;font-family: var(--bs-body-font-family); font-size: var(--bs-body-font-size); font-weight: var(--bs-body-font-weight); text-align: var(--bs-body-text-align);&quot;&gt;​&lt;/span&gt;&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अन्य शब्द और उनके उपसर्ग:-&lt;/strong&gt;

	&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:200px;&quot;&gt;
		&lt;tbody&gt;
			&lt;tr&gt;
				&lt;td&gt;&lt;strong&gt;शब्द&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
				&lt;td&gt;&lt;strong&gt;उपसर्ग&lt;/strong&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;अनुभव&lt;/td&gt;
				&lt;td&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;अनु&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;अपयश&lt;/td&gt;
				&lt;td&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;अप&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;आजीवन&lt;/td&gt;
				&lt;td&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;आ&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;उपवन&lt;/td&gt;
				&lt;td&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;उप&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
			&lt;tr&gt;
				&lt;td&gt;अवकाश&lt;/td&gt;
				&lt;td&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;अव&lt;/span&gt;&lt;/td&gt;
			&lt;/tr&gt;
		&lt;/tbody&gt;
	&lt;/table&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&amp;#39;छप्पय&amp;#39; रोला और उल्लाला छंदों के मेल से बनता है।&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;छप्पय मात्रिक विषम छन्द है। यह भी संयुक्त छन्द है, जो रोला (11+13) चार पाद तथा उल्लाला (15+13) के दो पाद के योग से बनता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;उदाहरण&lt;/strong&gt;:
	&lt;ul&gt;
		&lt;li&gt;नीलाम्बर परिधान हरित पट पर सुन्दर है।&lt;br /&gt;
		सूर्य-चन्द्र युग मुकुट, मेखला रत्नाकर है।&lt;br /&gt;
		नदिया प्रेम-प्रवाह, फूल -तो मंडन है।&lt;br /&gt;
		बंदी जन खग-वृन्द, शेषफन सिंहासन है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;उल्लाला:&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह अर्ध सममात्रिक छन्द है । उल्लाला में 28 मात्राएँ होते हैं जिसमें पहले और तीसरे चरण में 15-15 दूसरे और चौधे चरण में 13-13 मात्राएं होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;अतः उल्लाला छन्द = 15 + 13 = 28&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;हे शरण दायिनी देवि तू, करती सबका त्राण है।&lt;/li&gt;
	&lt;li&gt;हैं मातृ भूमि संतान हम, तू जननी तू प्राण है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण &amp;ndash;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;हे शरण दायिनी देवि तू,&amp;nbsp; करती सबका त्राण है।&lt;/li&gt;
	&lt;li&gt;S&amp;nbsp; I I I&amp;nbsp; S I S&amp;nbsp; &amp;nbsp;S I&amp;nbsp; &amp;nbsp;S&amp;nbsp; &amp;nbsp;I I S&amp;nbsp; I I S&amp;nbsp; &amp;nbsp;S I&amp;nbsp; &amp;nbsp;S = 15+13=28&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;रोला&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;यह&amp;nbsp; सममात्रिक छन्द है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;इसे &amp;lsquo;काव्य छन्द&amp;rsquo; के नाम से भी जाना जाता है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;इसमें कुल 24 मात्राएं होती है जिसमें 11 एवं 13 मात्राओं पर यति होता है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;कहने का तात्पर्य है कि पहले और तीसरे चरण में 11-11 तथा दूसरे और चौथे में 13-13 मात्राएं होती है। &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;यह दोहा का उल्टा होता है।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;​​&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण&lt;/span&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(58, 58, 58);   &quot;&gt;​&lt;/span&gt;जो जग हित, पर प्राण, निछावर है कर पाता।&lt;/li&gt;
	&lt;li&gt;जिसका तन है किसी, लोकहित में लग जाता।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण &lt;/strong&gt;&amp;ndash;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;जो&amp;nbsp; जग&amp;nbsp; हित&amp;nbsp; पर&amp;nbsp; प्राण,&amp;nbsp; निछावर&amp;nbsp; &amp;nbsp;है&amp;nbsp; कर&amp;nbsp; पाता।&lt;/li&gt;
	&lt;li&gt;S&amp;nbsp; &amp;nbsp; I I&amp;nbsp; &amp;nbsp; I I&amp;nbsp; &amp;nbsp; I I&amp;nbsp; &amp;nbsp;S I&amp;nbsp; &amp;nbsp; I S I I&amp;nbsp; &amp;nbsp; &amp;nbsp; S&amp;nbsp; &amp;nbsp;I I&amp;nbsp; &amp;nbsp;S S = 11 + 13 = 24&lt;/li&gt;
	&lt;li&gt;अतः यहाँ पर रोला छंद है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;strong&gt;दोहा&lt;/strong&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दोहा में चार चरण होते हैं। पहले और तीसरे चरण में तेरह-तेरह मात्राएँ तथा दूसरे और चौथे चरण में ग्यारह-ग्यारह मात्राएँ होती हैं। चरण के अन्त में यति होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;उदाहरण&lt;/strong&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मेरी भव बाधा हरो, राधा नागरि सोय।&lt;/li&gt;
	&lt;li&gt;जा तन की जाँई परे, श्याम हरित दुति होय॥&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण &lt;/strong&gt;&amp;ndash;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मेरी&amp;nbsp; भव&amp;nbsp; &amp;nbsp;बाधा&amp;nbsp; &amp;nbsp;हरो,&amp;nbsp; राधा&amp;nbsp; &amp;nbsp;नागरि&amp;nbsp; &amp;nbsp;सोय।&lt;/li&gt;
	&lt;li&gt;SS&amp;nbsp; &amp;nbsp;I I&amp;nbsp; &amp;nbsp; &amp;nbsp;S S&amp;nbsp; &amp;nbsp; I S&amp;nbsp; &amp;nbsp; S S&amp;nbsp; &amp;nbsp; S I I&amp;nbsp; &amp;nbsp; &amp;nbsp;S I&amp;nbsp; = 13 + 11 = 24&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;सोरठा&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सोरठा छंद में चार चरण होते हैं। पहले और तीसरे चरण में 11-11 मात्राएँ तथा दूसरे और चौथे चरण में 13-13 मात्राएँ होती हैं।चरण के अन्त में यति होती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;उदाहरण&lt;/span&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नील सरोरुह श्याम, तरुन अरुन वारिज नयन।&lt;/li&gt;
	&lt;li&gt;करहु सो मम उर धाम, सदा क्षीर सागर सयन ॥&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण &lt;/strong&gt;&amp;ndash;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नील&amp;nbsp; सरोरुह&amp;nbsp; श्याम,&amp;nbsp; तरुन&amp;nbsp; अरुन&amp;nbsp; वारिज&amp;nbsp; नयन।&lt;/li&gt;
	&lt;li&gt;S&amp;nbsp; I&amp;nbsp; &amp;nbsp;I S I I&amp;nbsp; &amp;nbsp; &amp;nbsp;S I&amp;nbsp; &amp;nbsp; &amp;nbsp;I I I&amp;nbsp; &amp;nbsp; I I I&amp;nbsp; &amp;nbsp; &amp;nbsp;S I I&amp;nbsp; &amp;nbsp; I I I&amp;nbsp; = 11 +13=24&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही उत्तर है - &amp;lsquo;&lt;strong&gt;अनावृष्टि&lt;/strong&gt;&amp;rsquo;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अतिवृष्टि &lt;/strong&gt;का विलोम &lt;u&gt;&lt;strong&gt;अनावृष्टि &lt;/strong&gt;&lt;/u&gt;होगा।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अतिवृष्टि &lt;/strong&gt;का अर्थ : बहुत अधिक मात्रा में बारिश होना।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अनावृष्टि &lt;/strong&gt;का अर्थ : वर्षा का अभाव।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;अन्य विकल्प:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वृष्टि&amp;nbsp;&lt;/strong&gt;का विलोम &lt;strong&gt;अनावृष्टि&amp;nbsp;&lt;/strong&gt;होगा।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मित &lt;/strong&gt;का अर्थ -&amp;nbsp;नपा तुला, सीमित।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;वृष्टि &lt;/strong&gt;का अर्थ -&amp;nbsp;पानी बरसना, वर्षा का जल।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;न्यून&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;का अर्थ -&amp;nbsp;कम, थोड़ा।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;न्यून &lt;/strong&gt;का विलोम&amp;nbsp;- अधिक&lt;span style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;strong&gt;विलोम शब्द के उदाहरण:-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;विषाद &lt;/strong&gt;&amp;ndash; हर्ष&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जय &lt;/strong&gt;&amp;ndash; पराजय&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;दुर्गति &lt;/strong&gt;&amp;ndash; सद्गति&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अल्पायु &lt;/strong&gt;&amp;ndash; दीर्घायु&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&lt;span lang=&quot;HI&quot; style=&quot;&quot;&gt;दिए गए विकल्पों में सही उत्तर&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;b&gt;&lt;span lang=&quot;HI&quot; style=&quot;&quot;&gt;विकल्प&lt;/span&gt;&lt;/b&gt;&lt;b&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;&quot;&gt;&amp;nbsp;4&amp;nbsp;&amp;lsquo;अनुप्रास&lt;/span&gt;&lt;/b&gt;&lt;b&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/b&gt;&lt;b&gt;&lt;span lang=&quot;HI&quot; style=&quot;&quot;&gt;अलंकार&lt;/span&gt;&lt;/b&gt;&lt;b&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;&quot;&gt;&amp;rsquo;&amp;nbsp;&lt;/span&gt;&lt;/b&gt;&lt;span lang=&quot;HI&quot; style=&quot;&quot;&gt;है। अन्य विकल्प इसके अनुचित उत्तर हैं।&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;&quot;&gt;&lt;o:p&gt;&lt;/o:p&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/quesImage303.png&quot; /&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;#39;कुल कानन कुंडल मोर पखा, उर पे बनमाल विराजति हैं।&amp;#39; में &amp;#39;क&amp;#39; वर्ण कई बार आया है इसलिए यहाँ अनुप्रास अलंकार है।&amp;nbsp;&lt;/li&gt;
	&lt;li style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;जहां एक ही वर्ण की आवृत्ति एक से अधिक बार हो, वहाँ अनुप्रास अलंकार होता है।&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;अन्य विकल्प: &lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;table align=&quot;left&quot; border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:67px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;अलंकार&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:340px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;परिभाषा&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;उदाहरण &lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:67px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;श्लेष &lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:340px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.1pt;&quot;&gt;जहां पर किसी एक शब्द का अनेक अर्थों में प्रयोग हो, वहाँ श्लेष अलंकार होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p&gt;मधुवन की छाती को देखो,&lt;/p&gt;

			&lt;p&gt;सूखी कितनी इसकी कलियाँ।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:67px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;उत्प्रेक्षा &lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:340px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.1pt;&quot;&gt;जहां समानता के कारण उपमेय में संभावना या कल्पना की जाए, वहाँ उत्प्रेक्षा अलंकार होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p&gt;सोहत ओढ़े पीत पट, स्याम सलोने गात। मनहुँ नीलमनि सैल पर, आतप परयौ प्रभात।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:67px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;उपमा &lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:340px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.1pt;&quot;&gt;जहां एक वस्तु या प्राणी की तुलना किसी दूससरी वस्तु या प्राणी से की जाए, वहाँ उपमा अलंकार होता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p&gt;सागर-सा गंभीर हृदय हो,&lt;/p&gt;

			&lt;p&gt;गिरि-सा ऊंचा हो जिसका मन।&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&amp;nbsp;&lt;/p&gt;

&lt;p style=&quot;margin: 0cm 0cm 7.5pt; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;&quot;&gt;&lt;img alt=&quot;&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/quesImage5630.png&quot; /&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:95px;height:54px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;अलंकार&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:434px;height:54px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.1pt;&quot;&gt;काव्य अथवा भाषा की शोभा बढ़ाने वाले मनोरंजक ढंग को अलंकार कहते हैं। अर्थात जिन गुण धर्मों द्वारा काव्य की शोभा बढ़ाई जाती है, उन्हें अलंकार कहा जाता है। इसके दो भेद हैं- शब्दालंकार और अर्थालंकार।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;दिए गए विकल्पों में से &amp;#39;&lt;strong&gt;कर्मधारय समास&amp;#39;&amp;nbsp;&lt;/strong&gt;सही उत्तर है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;कर्मधारय समास -&amp;nbsp;&lt;/span&gt;जिस समस्त-पद का उत्तरपद प्रधान हो तथा पूर्वपद व उत्तरपद,&lt;/li&gt;
	&lt;li&gt;में उपमान-उपमेय अथवा विशेषण-विशेष्य संबंध हो, कर्मधारय समास कहलाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मंदगति&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt; = मंद&amp;nbsp;+ गति&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;(विशेषण&amp;nbsp;+ विशेष्य)&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विग्रह - &lt;/span&gt;धीमी&amp;nbsp;है जो गति&amp;nbsp;।&lt;/li&gt;
	&lt;li&gt;अतः&amp;nbsp;मंदगति कर्मधारय समास का उदाहरण है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;समास -&amp;nbsp;&lt;/span&gt;अनेक शब्दों को संक्षिप्त करके नए शब्द बनाने की प्रक्रिया समास कहलाती है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;समास के भेद-&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;color: rgb(33, 37, 41); width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;समास&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;परिभाषा&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;उदाहरण&amp;nbsp;&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;तत्पुरुष समास&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;जिस समास में बाद का अथवा उत्तरपद प्रधान होता है तथा दोनों पदों के बीच का कारक-चिह्न लुप्त हो जाता है, उसे तत्पुरुष समास कहते है।&lt;/font&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;तुलसीकृत= तुलसी से कृत&lt;/font&gt;&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;चिड़ीमार चिड़ियों (को) मारनेवाला&lt;/font&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;कर्मधारय समास:&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;जिस समस्त-पद का उत्तरपद प्रधान हो तथा पूर्वपद व उत्तरपद में उपमान-उपमेय अथवा विशेषण-विशेष्य संबंध हो, कर्मधारय समास कहलाता है।&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;परमेश्र्वर = परम है जो ईश्र्वर&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;द्विगु समास&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&amp;nbsp;जिस समस्त-पद का पूर्वपद संख्यावाचक विशेषण हो, वह द्विगु&amp;nbsp; समास कहलाता है।&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;त्रिलोक = तीनों लोको का समाहार&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;बहुव्रीहि समास&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&amp;nbsp;समास में आये पदों को छोड़कर जब किसी अन्य पदार्थ की प्रधानता हो, तब उसे बहुव्रीहि समास कहते है।&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;विषधर = विष को धारण करने वाला (सर्प)&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;द्वन्द्व समास&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&amp;nbsp;जिस समस्त-पद के दोनों पद प्रधान हो तथा विग्रह करने पर &amp;#39;और&amp;#39;, &amp;#39;अथवा&amp;#39;, &amp;#39;या&amp;#39;, &amp;#39;एवं&amp;#39; लगता हो वह द्वन्द्व समास कहलाता है।&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;रात-दिन = रात और दिन&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;अव्ययीभाव समास&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;&amp;nbsp;जिस समास का पहला पद (पूर्वपद) अव्यय तथा प्रधान हो, उसे अव्ययीभाव समास कहते है।&lt;/font&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;font color=&quot;#58595b&quot;&gt;यथाविधि =&amp;nbsp; विधि के अनुसार&lt;/font&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;
